<template><Head title="Challan PDF" /><DealerLayout title="Challan PDF" eyebrow="Download service"><section class="grid gap-3 sm:grid-cols-3"><Metric label="Wallet balance" :value="money(walletBalance)" /><Metric label="Cost per report" :value="money(charge)" /><Metric label="Service status" :value="active?'Active':'Paused'" /></section><section class="mt-5 grid gap-5 rounded-lg border border-slate-200 bg-white p-5 shadow-sm xl:grid-cols-2 xl:items-center"><div><p class="text-xs font-semibold uppercase tracking-wide text-teal-700">Generate report</p><h2 class="mt-2 text-2xl font-semibold text-slate-950">Request an official Challan PDF.</h2><p class="mt-2 text-sm font-semibold text-slate-600">The wallet is charged only when the API returns a valid PDF.</p></div><form @submit.prevent="submit"><label><span class="mb-2 block text-sm font-semibold text-slate-700">Challan or vehicle number</span><input v-model="form.vehicle_number" class="dealer-input uppercase" maxlength="20" required /></label><button class="mt-3 w-full rounded-lg bg-slate-950 px-5 py-3 text-sm font-semibold text-white disabled:opacity-50" :disabled="form.processing||!active||walletBalance<charge">{{ form.processing?'Generating...':'Generate PDF' }}</button><p v-if="walletBalance<charge" class="mt-2 text-sm font-bold text-red-600">Insufficient balance. <Link :href="actions.wallet" class="underline">Recharge wallet</Link></p></form></section><section class="mt-5 overflow-hidden rounded-lg border border-slate-200 bg-white shadow-sm"><div class="border-b border-slate-100 px-5 py-4"><h3 class="text-xl font-semibold text-slate-950">Report history</h3></div><div class="overflow-x-auto"><table class="w-full min-w-[760px] text-left text-sm"><thead class="bg-slate-50 text-xs font-semibold uppercase tracking-wide text-slate-500"><tr><th class="px-5 py-3">Number</th><th class="px-5 py-3">Status</th><th class="px-5 py-3">Charge</th><th class="px-5 py-3">Date</th><th class="px-5 py-3 text-right">PDF</th></tr></thead><tbody class="divide-y divide-slate-100"><tr v-for="item in history.data" :key="item.id"><td class="px-5 py-4 font-semibold uppercase text-slate-950">{{ item.vehicle_number }}</td><td class="px-5 py-4"><span class="rounded-md px-2.5 py-1 text-xs font-semibold" :class="item.is_success?'bg-teal-50 text-teal-700':'bg-red-50 text-red-700'">{{ item.is_success?'Successful':'Failed' }}</span><p v-if="item.error" class="mt-1 max-w-xs truncate text-xs font-bold text-red-600">{{ item.error }}</p></td><td class="px-5 py-4 font-semibold">{{ money(item.charge) }}</td><td class="px-5 py-4 font-semibold text-slate-600">{{ item.created_at }}</td><td class="px-5 py-4 text-right"><a v-if="item.pdf_url" :href="item.pdf_url" target="_blank" rel="noopener noreferrer" class="rounded-lg bg-slate-950 px-3 py-2 text-xs font-semibold text-white">Open PDF</a><span v-else>-</span></td></tr><tr v-if="!history.data.length"><td colspan="5" class="px-5 py-14 text-center font-semibold text-slate-950">No reports yet</td></tr></tbody></table></div><div class="border-t border-slate-100 px-5 py-4"><PaginationLinks :links="history.links" /></div></section></DealerLayout></template>
<script setup lang="ts">import{defineComponent,h}from'vue';import{Head,Link,useForm}from'@inertiajs/vue3';import DealerLayout from '@/Layouts/DealerLayout.vue';import PaginationLinks from '@/Components/Admin/PaginationLinks.vue';const props=defineProps<{history:any;charge:number;walletBalance:number;active:boolean;actions:{search:string;history:string;wallet:string}}>();const form=useForm({vehicle_number:''});const submit=()=>form.post(props.actions.search,{preserveScroll:true});const money=(v:number)=>`Rs ${new Intl.NumberFormat('en-IN',{minimumFractionDigits:2,maximumFractionDigits:2}).format(Number(v||0))}`;const Metric=defineComponent({props:{label:{type:String,required:true},value:{type:[String,Number],required:true}},setup(p){return()=>h('div',{class:'rounded-lg border border-slate-200 bg-white p-4 shadow-sm'},[h('p',{class:'text-2xl font-semibold text-slate-950'},p.value),h('p',{class:'mt-1 text-xs font-semibold uppercase tracking-wide text-slate-500'},p.label)]);}});</script>
